class Solution {
public:
    int magicalString(int n) {
        string s = "122";
        int i = 2;
        while (s.size() < n) {
            int count = s[i++] - '0';
            char c = (s.back() == '1') ? '2' : '1';
            for (int j = 0; j < count; ++j) {
                s += c;
            }
        }
        int count = 0;
        for (i = 0; i < n; ++i) {
            if (s[i] == '1') {
                count++;
            }
        }
        return count;
    }
};
